output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(COUNT(DISTINCT ?island) AS ?count) WHERE {
  ?island wdt:P31 wd:Q445655 ; wdt:P131 wd:Q168243 ; wdt:P1082 ?population .
  FILTER(?population > 0)
}

args.sparql:
SELECT (COUNT(DISTINCT ?island) AS ?count)
WHERE {
  ?island wdt:P31 wd:Q445655;  # instance of island
         wdt:P131 wd:Q22064;  # located in Jeju Province
         wdt:P1082 ?population.
}

SELECT (COUNT(DISTINCT ?island) AS ?count)
WHERE {
  ?island wdt:P31 wd:Q445655;  # instance of island
         wdt:P131 wd:Q168243;  # located in Jeju Special Self-Governing Province
         wdt:P1082 ?population.
}

SELECT ?season (MIN(?episodes) AS ?min_episodes)
WHERE {
  ?season wdt:P179 wd:Q18230303;
         wdt:P919 ?episodes.
}
GROUP BY ?season
ORDER BY ?min_episodes
LIMIT 1

SELECT ?season ?episodes WHERE {
  wd:Q18230303 wdt:P179 ?season;
  ?season wdt:P1627 ?episodes.
} ORDER BY ?episodes LIMIT 1

SELECT ?season ?episodes WHERE {
  wd:Q18230303 wdt:P179 ?season.
  ?season wdt:P1627 ?episodes.
} ORDER BY ASC(?episodes)
LIMIT 1

SELECT (COUNT(DISTINCT ?island) AS ?count)
WHERE {
  ?island wdt:P31 wd:Q445655;
         wdt:P131 wd:Q168243;
         wdt:P1082 ?population.
  FILTER (?population > 0)
}

SELECT (COUNT(DISTINCT ?island) AS ?count)
WHERE {
  ?island wdt:P31 wd:Q445655;
         wdt:P131 wd:Q168243;
         wdt:P1082 ?population.
  FILTER (?population > 0)
}
